const binaryKeys = Object.keys($binary || {});
const fileKey = binaryKeys[0];
const file = fileKey ? $binary[fileKey] : null;

if (!file) {
  throw new Error('No file uploaded. Send a PDF/DOCX/TXT file as binary form-data.');
}

const allowedExtensions = ['pdf', 'docx', 'txt'];
const fileName = file.fileName || 'uploaded-file';
const extension = fileName.split('.').pop().toLowerCase();

if (!allowedExtensions.includes(extension)) {
  throw new Error(`Unsupported file type: ${extension}. Allowed: PDF, DOCX, TXT.`);
}

const maxSizeMb = 25;
const sizeMb = (file.fileSize || 0) / 1024 / 1024;
if (sizeMb > maxSizeMb) {
  throw new Error(`File too large: ${sizeMb.toFixed(2)} MB. Max allowed: ${maxSizeMb} MB.`);
}

return [{
  json: {
    fileName,
    extension,
    fileKey,
    sourceType: 'user_upload',
    uploadedAt: new Date().toISOString(),
    status: 'validated'
  },
  binary: $binary
}];

const text = $json.text || $json.extractedText || '';
const fileName = $('2. Check Uploaded File').first().json.fileName;
const sourceType = $('2. Check Uploaded File').first().json.sourceType;

if (!text.trim()) {
  throw new Error('No text extracted from uploaded file.');
}

const words = text.replace(/\s+/g, ' ').trim().split(' ');
const chunkSize = 420;
const overlap = 60;
const chunks = [];

for (let start = 0; start < words.length; start += chunkSize - overlap) {
  const chunkWords = words.slice(start, start + chunkSize);
  if (chunkWords.length < 30) continue;
  chunks.push({
    chunkId: `${fileName.replace(/[^a-zA-Z0-9]/g, '_')}_${chunks.length + 1}`,
    fileName,
    sourceType,
    chunkIndex: chunks.length + 1,
    text: chunkWords.join(' '),
    tokenEstimate: Math.ceil(chunkWords.length * 1.35),
    createdAt: new Date().toISOString()
  });
}

return chunks.map(chunk => ({ json: chunk }));

const source = $('4. Split Text into Chunks').item.json;
const embedding = $json.data?.[0]?.embedding || $json.embedding;

if (!embedding) {
  throw new Error('Embedding API did not return an embedding vector.');
}

return [{
  json: {
    id: source.chunkId,
    vector: embedding,
    payload: {
      fileName: source.fileName,
      sourceType: source.sourceType,
      chunkIndex: source.chunkIndex,
      text: source.text,
      tokenEstimate: source.tokenEstimate,
      createdAt: source.createdAt
    }
  }
}];

