const body = $json.body || $json;
const question = body.question || body.message || '';
const userId = body.userId || 'anonymous-user';
const sessionId = body.sessionId || `session-${Date.now()}`;

if (!question.trim()) {
  throw new Error('Missing question. Send { question, userId, sessionId } in the request body.');
}

const lower = question.toLowerCase();
let intent = 'knowledge_answer';
if (lower.includes('order') || lower.includes('refund') || lower.includes('ticket') || lower.includes('account')) {
  intent = 'support_lookup';
}
if (lower.includes('summarize') || lower.includes('summary')) {
  intent = 'summarization';
}

return [{
  json: {
    question,
    userId,
    sessionId,
    intent,
    cacheKey: `${userId}:${question.trim().toLowerCase()}`,
    maxRetrievedChunks: intent === 'summarization' ? 6 : 4,
    requestedAt: new Date().toISOString()
  }
}];

