const embedding = $json.data?.[0]?.embedding || $json.embedding;
const request = $('10. Read Question and Find Intent').first().json;
if (!embedding) {
  throw new Error('Query embedding was not returned.');
}
return [{
  json: {
    vector: embedding,
    question: request.question,
    userId: request.userId,
    sessionId: request.sessionId,
    intent: request.intent,
    cacheKey: request.cacheKey,
    maxRetrievedChunks: request.maxRetrievedChunks
  }
}];

const request = $('15. Prepare Vector Search').first().json;
const results = $json.result || $json.matches || $json.points || [];

const chunks = results
  .map((item, index) => ({
    rank: index + 1,
    score: item.score || item.similarity || 0,
    fileName: item.payload?.fileName || item.metadata?.fileName || 'unknown-source',
    chunkIndex: item.payload?.chunkIndex || item.metadata?.chunkIndex || index + 1,
    text: item.payload?.text || item.metadata?.text || item.text || ''
  }))
  .filter(chunk => chunk.text)
  .slice(0, request.maxRetrievedChunks);

const context = chunks.map(chunk => `[Source: ${chunk.fileName}, chunk ${chunk.chunkIndex}, score ${chunk.score}]\n${chunk.text}`).join('\n\n---\n\n');

return [{
  json: {
    ...request,
    retrievedChunks: chunks,
    context,
    retrievalSummary: `${chunks.length} chunks selected for final answer.`
  }
}];

const rag = $('17. Select Best Chunks').first().json;
const memory = $json || {};
const needsSupportLookup = rag.intent === 'support_lookup';

return [{
  json: {
    ...rag,
    memory: {
      shortTermSummary: memory.shortTermSummary || '',
      longTermFacts: memory.longTermFacts || [],
      userPreferences: memory.userPreferences || {}
    },
    needsSupportLookup
  }
}];

const base = $('19. Decide If Tool Is Needed').first().json;
const toolResult = $json || {};
return [{
  json: {
    ...base,
    toolResult
  }
}];

const model = $json.intent === 'knowledge_answer' ? 'gpt-4.1-mini' : 'gpt-4.1';
const systemPrompt = 'You are a production support/research/document analysis agent. Answer using retrieved context and tool results. Cite sources when available. If evidence is missing, say what is missing instead of guessing. Keep the answer clear and useful.';
const userPrompt = `Question: ${$json.question}\n\nRetrieved context:\n${$json.context}\n\nMemory:\n${JSON.stringify($json.memory)}\n\nTool result:\n${JSON.stringify($json.toolResult)}`;

return [{
  json: {
    ...$json,
    llmRequest: {
      model,
      temperature: 0.2,
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ]
    }
  }
}];

const source = $('23. Prepare Final AI Prompt').first().json;
const answer = $json.choices?.[0]?.message?.content || $json.answer || '';
const usage = $json.usage || {};

return [{
  json: {
    ...source,
    answer,
    modelUsage: usage,
    sources: source.retrievedChunks.map(chunk => ({
      fileName: chunk.fileName,
      chunkIndex: chunk.chunkIndex,
      score: chunk.score
    })),
    memoryUpdate: {
      latestQuestion: source.question,
      latestAnswerSummary: answer.slice(0, 700),
      updatedAt: new Date().toISOString()
    }
  }
}];

